//! Architecture tests for `version` module (auto-generated by zmodu).
//! Verifies module contracts, dependency integrity, and naming conventions.

const std = @import("std");
const zigmodu = @import("zigmodu");

test "version - architecture: no self dependency" {
    const allocator = std.testing.allocator;
    var modules = zigmodu.ApplicationModules.init(allocator);
    defer modules.deinit();

    try modules.register(zigmodu.ModuleInfo.init("version", "version module", &.{}));

    var tester = zigmodu.ArchitectureTester.init(allocator, &modules);
    defer tester.deinit();

    try tester.ruleNoSelfDependency();
    try std.testing.expectEqual(@as(usize, 0), tester.getViolationCountBySeverity(.err));
}

